	}

	if parsedURL.Scheme == "" || parsedURL.Host == "" {
		return "invalid-url"
	}

	path := parsedURL.EscapedPath()
	if path == "" {
		return parsedURL.Scheme + "://" + parsedURL.Host
	}

	return parsedURL.Scheme + "://" + parsedURL.Host + path
